function getExtrudeFeature(
  engine: CadEngine,
  featureId: string
): ExtrudeFeature {
  const feature = engine.getDocument().features.get(featureId);

  if (!feature || feature.kind !== "extrude") {
    throw new Error(`Expected extrude feature: ${featureId}`);
  }

  return feature;
}

