function readParameterEvaluation(
  engine: CadEngine
): ProjectParameterEvaluationQueryResponse {
  const response = engine.executeQuery({
    version: "cadops.v1",
    query: { query: "project.parameterEvaluation" }
  });

  if (!response.ok || response.query !== "project.parameterEvaluation") {
    throw new Error("Expected project.parameterEvaluation response.");
  }

  return response;
}

function createRectangleExtrudeEngine(): CadEngine {
  const engine = new CadEngine();

  engine.applyBatch([
    { op: "sketch.create", id: "sketch_1", name: "Profile", plane: "XY" },
    {
      op: "sketch.addRectangle",
      sketchId: "sketch_1",
      id: "rect_1",
      center: [0, 0],
      width: 4,
      height: 2
    },
    {
      op: "feature.extrude",
      id: "feat_rect_1",
      bodyId: "body_rect_1",
      sketchId: "sketch_1",
      entityId: "rect_1",
      depth: 3
    }
  ]);

  return engine;
}

function createCircleExtrudeEngine(): CadEngine {
  const engine = new CadEngine();

  engine.applyBatch([
    { op: "sketch.create", id: "sketch_1", name: "Profile", plane: "XY" },
    {
      op: "sketch.addCircle",
      sketchId: "sketch_1",
      id: "circle_1",
      center: [0, 0],
      radius: 2
    },
    {
      op: "feature.extrude",
      id: "feat_circle_1",
      bodyId: "body_circle_1",
      sketchId: "sketch_1",
      entityId: "circle_1",
      depth: 4
    }
  ]);

  return engine;
}

