function createV14CircleSidePlaneHoleCheckpointPayload(): NonNullable<
  NonNullable<
    Parameters<typeof exportCadProjectToWcad>[1]
  >["topologyCheckpoints"]
>[number] {
  const topologyPayload = createCheckpointTopologyPayload([
    {
      localId: "checkpoint-local-circle-body",
      kind: "body",
      source: "kernel-derived",
      signature: "circle_body_signature",
      bounds: {
        min: [-2, -2, 0],
        max: [2, 2, 4]
      }
    }
  ]);

  return {
    checkpointId: "checkpoint_circle_1",
    bodyId: "body_circle_1",
    sourceFeatureId: "feat_circle_1",
    kernel: {
      boundary: "geometry-kernel",
      snapshotAlgorithm: "partbench-derived-topology-snapshot-v1"
    },
    tolerance: {
      linearTolerance: 0.001,
      angularToleranceDegrees: 0.01
    },
    brepBytes: new TextEncoder().encode("circle side-plane hole brep bytes"),
    topologyBytes: encodeCanonicalCbor(topologyPayload),
    signatureBytes: encodeCanonicalCbor(
      createCheckpointSignaturePayload("checkpoint_circle_1", topologyPayload)
    )
  };
}

type CheckpointTopologyEntityFixture =
  CadBodyExactTopologySnapshot["entities"][number];

function createCheckpointTopologyPayload(
  entities: readonly CheckpointTopologyEntityFixture[] = []
): CadBodyExactTopologySnapshot {
  const counts = {
    bodyCount: 0,
    solidCount: 0,
    faceCount: 0,
    wireCount: 0,
    edgeCount: 0,
    vertexCount: 0,
    loopCount: 0,
    coedgeCount: 0,
    axisCount: 0
  };

  for (const entity of entities) {
    switch (entity.kind) {
      case "body":
        counts.bodyCount += 1;
        break;
      case "solid":
        counts.solidCount += 1;
        break;
      case "face":
        counts.faceCount += 1;
        break;
      case "wire":
        counts.wireCount += 1;
        break;
      case "edge":
        counts.edgeCount += 1;
        break;
      case "vertex":
        counts.vertexCount += 1;
        break;
      case "loop":
        counts.loopCount += 1;
        break;
      case "coedge":
        counts.coedgeCount += 1;
        break;
      case "axis":
        counts.axisCount += 1;
        break;
    }
  }

  return {
    source: "kernel-derived",
    status: "ready",
    entityCounts: counts,
    entityCount: entities.length,
    entities,
    unsupportedEntityKinds: [],
    adjacencyAvailable: true,
    signatureAlgorithm: "partbench-derived-topology-snapshot-v1",
    signature: "topology_signature",
    diagnostics: []
  };
}

function createCheckpointSignaturePayload(
  checkpointId: string,
  topology: CadBodyExactTopologySnapshot
): unknown {
  return {
    checkpointId,
    signatureAlgorithm: topology.signatureAlgorithm,
    signature: topology.signature,
    entityCount: topology.entityCount,
    entities: topology.entities.map((entity) => ({
      localId: entity.localId,
      kind: entity.kind,
      signature: entity.signature
    }))
  };
}

