function createTopologyEdgeAnchorEngine(
  options: {
    readonly anchorId?: string;
    readonly entityKind?: "face" | "edge" | "vertex" | "body" | "axis";
    readonly bodyId?: string;
    readonly stableId?: string;
    readonly checkpointStatus?:
      | "active"
      | "stale"
      | "missing"
      | "unsupported"
      | "failed";
    readonly sourceSemanticRole?: string;
    readonly anchorState?:
      | "active"
      | "replaced"
      | "split"
      | "merged"
      | "ambiguous"
      | "deleted"
      | "stale"
      | "missing"
      | "unsupported"
      | "repair-needed"
      | "failed";
  } = {}
): CadEngine {
  const baseEngine = createRectangleExtrudeEngine();
  const baseDocument = baseEngine.getDocument();
  const topologyIdentity = createEmptyTopologyIdentitySourceSnapshot();
  const paths = createWcadV2CheckpointEntryPaths("checkpoint_1");
  const sourceIdentity = {
    algorithm: "partbench-source-v1" as const,
    sha256: "1111111111111111111111111111111111111111111111111111111111111111"
  };

  return new CadEngine({
    ...baseDocument,
    topologyIdentity: {
      ...topologyIdentity,
      checkpoints: [
        {
          checkpointId: "checkpoint_1",
          bodyId: "body_rect_1",
          sourceFeatureId: "feat_rect_1",
          sourceIdentity,
          packageVersion: "partbench.wcad.v2" as const,
          projectSchemaVersion: CAD_PROJECT_FORMAT_VERSION_V18,
          brepEntryPath: paths.brep,
          topologyEntryPath: paths.topology,
          signatureEntryPath: paths.signature,
          status: options.checkpointStatus ?? "active",
          diagnostics: []
        }
      ],
      anchors: [
        {
          anchorId: options.anchorId ?? "anchor_edge_1",
          entityKind: options.entityKind ?? "edge",
          bodyId: options.bodyId ?? "body_rect_1",
          checkpointId: "checkpoint_1",
          checkpointEntityId: "checkpoint-local-edge-1",
          sourceFeatureId: "feat_rect_1",
          ...(options.stableId === undefined
            ? { stableId: "generated:edge:body_rect_1:start:uMin" }
            : options.stableId.length > 0
              ? { stableId: options.stableId }
              : {}),
          sourceSemanticRole: options.sourceSemanticRole ?? "start uMin edge",
          signatureHash: "edge_signature_1",
          state: options.anchorState ?? "active",
          diagnostics: []
        }
      ]
    }
  });
}

function createTopologyCheckpointEngine(
  options: {
    readonly includeReplacementCheckpoint?: boolean;
  } = {}
): CadEngine {
  const baseEngine = createRectangleExtrudeEngine();
  const baseDocument = baseEngine.getDocument();
  const topologyIdentity = createEmptyTopologyIdentitySourceSnapshot();
  const sourceIdentity = {
    algorithm: "partbench-source-v1" as const,
    sha256: "1111111111111111111111111111111111111111111111111111111111111111"
  };
  const checkpoint1Paths = createWcadV2CheckpointEntryPaths("checkpoint_1");
  const checkpoint2Paths = createWcadV2CheckpointEntryPaths("checkpoint_2");
  const checkpoints: CadTopologyCheckpointSourceRecord[] = [
    {
      checkpointId: "checkpoint_1",
      bodyId: "body_rect_1",
      sourceFeatureId: "feat_rect_1",
      sourceIdentity,
      packageVersion: "partbench.wcad.v2",
      projectSchemaVersion: CAD_PROJECT_FORMAT_VERSION_V18,
      brepEntryPath: checkpoint1Paths.brep,
      topologyEntryPath: checkpoint1Paths.topology,
      signatureEntryPath: checkpoint1Paths.signature,
      status: "active",
      diagnostics: []
    }
  ];

  if (options.includeReplacementCheckpoint) {
    checkpoints.push({
      checkpointId: "checkpoint_2",
      bodyId: "body_rect_1",
      sourceFeatureId: "feat_rect_1",
      sourceIdentity,
      packageVersion: "partbench.wcad.v2",
      projectSchemaVersion: CAD_PROJECT_FORMAT_VERSION_V18,
      brepEntryPath: checkpoint2Paths.brep,
      topologyEntryPath: checkpoint2Paths.topology,
      signatureEntryPath: checkpoint2Paths.signature,
      status: "active",
      diagnostics: []
    });
  }

  return new CadEngine({
    ...baseDocument,
    topologyIdentity: {
      ...topologyIdentity,
      checkpoints
    }
  });
}

function createTopologyAnchorMatchResult(
  state: CadTopologyMatchResult["state"],
  confidence: CadTopologyMatchResult["confidence"] = state === "active"
    ? "exact"
    : "low"
): CadTopologyMatchResult {
  return {
    anchorId: "anchor_face_1",
    previousStableId: "generated:face:body_rect_1:endCap",
    previousCheckpointId: "checkpoint_1",
    ...(state === "deleted"
      ? {}
      : {
          candidateStableId: "generated:face:body_rect_1:endCap",
          candidateCheckpointId: "checkpoint_2"
        }),
    entityKind: "face",
    state,
    confidence,
    confidenceScore: confidence === "exact" ? 1 : 0.35,
    evidenceCount: 1,
    evidence: [
      {
        kind: "sourceLineage",
        confidence,
        message: `Synthetic ${state} topology match evidence.`
      }
    ],
    diagnosticCount: state === "active" ? 0 : 1,
    diagnostics:
      state === "active"
        ? []
        : [
            {
              code:
                state === "deleted"
                  ? "TOPOLOGY_MATCH_DELETED"
                  : state === "ambiguous" || state === "split"
                    ? "TOPOLOGY_MATCH_AMBIGUOUS"
                    : state === "replaced"
                      ? "TOPOLOGY_MATCH_REPLACED"
                      : "TOPOLOGY_MATCH_LOW_CONFIDENCE",
              status: "deferred",
              severity: "warning",
              message: `Synthetic ${state} topology match diagnostic.`,
              entityKind: "face",
              bodyId: "body_rect_1",
              featureId: "feat_rect_1",
              checkpointId: "checkpoint_1",
              anchorId: "anchor_face_1"
            }
          ]
  };
}

function createTopologySnapshot(
  entities: readonly ({
    readonly localId: string;
    readonly kind: string;
    readonly signature: string;
    readonly bounds?: CadBodyExactTopologySnapshot["entities"][number]["bounds"];
  } & Partial<
    Omit<
      CadBodyExactTopologySnapshot["entities"][number],
      "localId" | "kind" | "source" | "signature" | "bounds"
    >
  >)[]
): CadBodyExactTopologySnapshot {
  const counts = {
    bodyCount: entities.filter((entity) => entity.kind === "body").length,
    solidCount: entities.filter((entity) => entity.kind === "solid").length,
    faceCount: entities.filter((entity) => entity.kind === "face").length,
    wireCount: entities.filter((entity) => entity.kind === "wire").length,
    edgeCount: entities.filter((entity) => entity.kind === "edge").length,
    vertexCount: entities.filter((entity) => entity.kind === "vertex").length,
    loopCount: entities.filter((entity) => entity.kind === "loop").length,
    coedgeCount: entities.filter((entity) => entity.kind === "coedge").length,
    axisCount: entities.filter((entity) => entity.kind === "axis").length
  };

  return {
    source: "kernel-derived",
    status: "ready",
    entityCounts: counts,
    entityCount: entities.length,
    entities: entities.map((entity) => ({
      localId: entity.localId,
      kind: entity.kind as CadBodyExactTopologySnapshot["entities"][number]["kind"],
      source: "kernel-derived" as const,
      signature: entity.signature,
      ...(entity.bounds ? { bounds: entity.bounds } : {}),
      ...(entity.surfaceClass ? { surfaceClass: entity.surfaceClass } : {}),
      ...(entity.curveClass ? { curveClass: entity.curveClass } : {}),
      ...(entity.point ? { point: entity.point } : {}),
      ...(entity.midpoint ? { midpoint: entity.midpoint } : {}),
      ...(entity.normal ? { normal: entity.normal } : {}),
      ...(entity.axis ? { axis: entity.axis } : {}),
      ...(entity.radius !== undefined ? { radius: entity.radius } : {}),
      ...(entity.area !== undefined ? { area: entity.area } : {}),
      ...(entity.length !== undefined ? { length: entity.length } : {}),
      ...(entity.adjacency ? { adjacency: entity.adjacency } : {}),
      ...(entity.orientation ? { orientation: entity.orientation } : {}),
      ...(entity.loopRole ? { loopRole: entity.loopRole } : {}),
      ...(entity.relationships ? { relationships: entity.relationships } : {})
    })),
    unsupportedEntityKinds: [],
    adjacencyAvailable: true,
    signatureAlgorithm: "partbench-derived-topology-snapshot-v1",
    signature: entities.map((entity) => entity.signature).join("|"),
    diagnostics: []
  };
}

function createTopologyMatchSnapshotInput({
  checkpointId,
  bodyId,
  sourceFeatureId = "feature_1",
  entities,
  sourceIdentitySha = "aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa"
}: {
  readonly checkpointId: string;
  readonly bodyId: string;
  readonly sourceFeatureId?: string;
  readonly entities: readonly ({
    readonly localId: string;
    readonly kind: string;
    readonly signature: string;
    readonly bounds?: CadBodyExactTopologySnapshot["entities"][number]["bounds"];
  } & Partial<
    Omit<
      CadBodyExactTopologySnapshot["entities"][number],
      "localId" | "kind" | "source" | "signature" | "bounds"
    >
  >)[];
  readonly sourceIdentitySha?: string;
}) {
  return {
    checkpointId,
    bodyId,
    sourceFeatureId,
    sourceIdentity: {
      algorithm: "partbench-source-v1" as const,
      sha256: sourceIdentitySha
    },
    topologySnapshot: createTopologySnapshot(entities)
  };
}

function readTopologyMatchSnapshots(
  response: ReturnType<CadEngine["executeQuery"]>
): TopologyMatchSnapshotsQueryResponse {
  if (!response.ok || response.query !== "topology.matchSnapshots") {
    throw new Error("Expected topology.matchSnapshots response.");
  }

  return response;
}

