function createExactMetadataSnapshot(input: {
  readonly bodyId: string;
  readonly sourceIdentitySignature: string;
  readonly volume?: number;
  readonly faceCount?: number;
  readonly edgeCount?: number;
  readonly vertexCount?: number;
  readonly includeTopologySnapshot?: boolean;
  readonly topologySnapshotStatus?: CadBodyExactTopologySnapshot["status"];
  readonly topologyEntities?: CadBodyExactTopologySnapshot["entities"];
}): CadBodyDerivedExactMetadataSnapshot {
  const defaultFaceCount = input.faceCount ?? 6;
  const defaultEdgeCount = input.edgeCount ?? 12;
  const defaultVertexCount = input.vertexCount ?? 8;
  const topologyEntities = input.topologyEntities ?? [
    {
      localId: "snapshot-local:body:0",
      kind: "body" as const,
      source: "kernel-derived" as const,
      signature: "topology-body-test"
    },
    {
      localId: "snapshot-local:solid:0",
      kind: "solid" as const,
      source: "kernel-derived" as const,
      signature: "topology-solid-test"
    },
    ...Array.from({ length: defaultFaceCount }, (_, index) => ({
      localId: `snapshot-local:face:${index}`,
      kind: "face" as const,
      source: "kernel-derived" as const,
      signature: `topology-face-test-${index}`
    })),
    ...Array.from({ length: 6 }, (_, index) => ({
      localId: `snapshot-local:wire:${index}`,
      kind: "wire" as const,
      source: "kernel-derived" as const,
      signature: `topology-wire-test-${index}`
    })),
    ...Array.from({ length: defaultEdgeCount }, (_, index) => ({
      localId: `snapshot-local:edge:${index}`,
      kind: "edge" as const,
      source: "kernel-derived" as const,
      signature: `topology-edge-test-${index}`
    })),
    ...Array.from({ length: defaultVertexCount }, (_, index) => ({
      localId: `snapshot-local:vertex:${index}`,
      kind: "vertex" as const,
      source: "kernel-derived" as const,
      signature: `topology-vertex-test-${index}`
    }))
  ];
  const countEntities = (
    kind: CadBodyExactTopologySnapshot["entities"][number]["kind"]
  ) => topologyEntities.filter((entity) => entity.kind === kind).length;
  const topologySnapshot = input.includeTopologySnapshot
    ? {
        source: "kernel-derived" as const,
        status: input.topologySnapshotStatus ?? ("partial" as const),
        entityCounts: {
          bodyCount: countEntities("body"),
          solidCount: countEntities("solid"),
          faceCount: countEntities("face"),
          wireCount: countEntities("wire"),
          edgeCount: countEntities("edge"),
          vertexCount: countEntities("vertex"),
          loopCount: countEntities("loop"),
          coedgeCount: countEntities("coedge"),
          axisCount: countEntities("axis")
        },
        entityCount: topologyEntities.length,
        entities: topologyEntities,
        unsupportedEntityKinds: ["loop", "coedge", "axis"] as const,
        adjacencyAvailable: false,
        signatureAlgorithm: "partbench-derived-topology-snapshot-v1" as const,
        signature: "topology-snapshot-test",
        diagnostics: [
          {
            code: "GEOMETRY_TOPOLOGY_SNAPSHOT_EXTRACTED",
            message: "Derived topology snapshot extracted."
          }
        ]
      }
    : undefined;

  return {
    bodyId: input.bodyId,
    sourceIdentitySignature: input.sourceIdentitySignature,
    status: "ready",
    metadata: {
      source: "kernel-derived",
      confidence: "kernel-derived",
      bounds: {
        min: [0, 0, 0],
        max: [4, 2, 3],
        size: [4, 2, 3],
        center: [2, 1, 1.5]
      },
      volume: input.volume ?? 24,
      surfaceArea: 52,
      centroid: [2, 1, 1.5],
      topologyCounts: {
        solidCount: 1,
        faceCount: input.faceCount ?? 6,
        edgeCount: input.edgeCount ?? 12,
        vertexCount: input.vertexCount ?? 8
      },
      ...(topologySnapshot ? { topologySnapshot } : {}),
      diagnostics: []
    }
  };
}

function validateEngineGeneratedReference(
  engine: CadEngine,
  options: Omit<
    Parameters<typeof validateGeneratedReference>[0],
    "document" | "ownerPartId" | "bodyExists"
  >
): ReturnType<typeof validateGeneratedReference> {
  const structure = engine.executeQuery({
    version: "cadops.v1",
    query: { query: "project.structure" }
  });

  if (!structure.ok || structure.query !== "project.structure") {
    throw new Error("Expected project structure response.");
  }

  return validateGeneratedReference({
    ...options,
    document: engine.getDocument(),
    ownerPartId: DEFAULT_PART_ID,
    bodyExists: (bodyId) => structure.bodies.some((body) => body.id === bodyId)
  });
}

