  it("updates, renames, and deletes sketch source data with undo and redo", () => {
    const engine = new CadEngine();

    engine.applyBatch([
      { op: "sketch.create", id: "sketch_1", name: "Profile", plane: "XZ" },
      {
        op: "sketch.addCircle",
        sketchId: "sketch_1",
        id: "circle_1",
        center: [0, 0],
        radius: 1
      }
    ]);

    const result = engine.applyBatch([
      {
        op: "sketch.updateEntity",
        sketchId: "sketch_1",
        entity: {
          id: "circle_1",
          kind: "circle",
          center: [2, 3],
          radius: 4
        }
      },
      { op: "sketch.rename", id: "sketch_1", name: "Updated profile" },
      {
        op: "sketch.deleteEntity",
        sketchId: "sketch_1",
        entityId: "circle_1"
      }
    ]);

    expect(result.document.sketches.get("sketch_1")?.name).toBe(
      "Updated profile"
    );
    expect(
      result.document.sketches.get("sketch_1")?.entities.has("circle_1")
    ).toBe(false);
    expect(result.transaction.diff.sketches).toMatchObject({
      modified: [{ id: "sketch_1" }],
      entitiesModified: [
        { sketchId: "sketch_1", id: "circle_1", kind: "circle" }
      ],
      entitiesDeleted: [
        { sketchId: "sketch_1", id: "circle_1", kind: "circle" }
      ]
    });

    engine.undo();
    expect(engine.getDocument().sketches.get("sketch_1")?.name).toBe("Profile");
    expect(
      engine.getDocument().sketches.get("sketch_1")?.entities.has("circle_1")
    ).toBe(true);

    engine.redo();
    expect(
      engine.getDocument().sketches.get("sketch_1")?.entities.has("circle_1")
    ).toBe(false);
  });

  it("deletes dimensions and constraints that reference deleted sketch entities", () => {
    const engine = new CadEngine();

    engine.applyBatch([
      { op: "sketch.create", id: "sketch_1", name: "Profile", plane: "XY" },
      {
        op: "sketch.addPoint",
        sketchId: "sketch_1",
        id: "point_fixed",
        point: [0, 0]
      },
      {
        op: "sketch.addPoint",
        sketchId: "sketch_1",
        id: "point_coincident",
        point: [0, 0]
      },
      {
        op: "sketch.addPoint",
        sketchId: "sketch_1",
        id: "point_midpoint",
        point: [2, 0]
      },
      {
        op: "sketch.addLine",
        sketchId: "sketch_1",
        id: "line_1",
        start: [0, 0],
        end: [4, 0]
      },
      {
        op: "sketch.addLine",
        sketchId: "sketch_1",
        id: "line_2",
        start: [0, 1],
        end: [4, 1]
      },
      {
        op: "sketch.dimension.create",
        id: "dim_line_2_length",
        name: "Line 2 length",
        sketchId: "sketch_1",
        entityId: "line_2",
        target: { entityKind: "line", role: "length" },
        value: 4
      },
      {
        op: "sketch.constraint.create",
        id: "fixed_point",
        name: "Fixed point",
        sketchId: "sketch_1",
        kind: "fixed",
        target: { entityId: "point_fixed", role: "position" }
      },
      {
        op: "sketch.constraint.create",
        id: "coincident_point",
        name: "Point coincident",
        sketchId: "sketch_1",
        kind: "coincident",
        primaryTarget: { entityId: "line_1", role: "start" },
        secondaryTarget: { entityId: "point_coincident", role: "position" }
      },
      {
        op: "sketch.constraint.create",
        id: "midpoint_point",
        name: "Point midpoint",
        sketchId: "sketch_1",
        kind: "midpoint",
        lineEntityId: "line_1",
        target: { entityId: "point_midpoint", role: "position" }
      },
      {
        op: "sketch.constraint.create",
        id: "parallel_lines",
        name: "Parallel lines",
        sketchId: "sketch_1",
        kind: "parallel",
        primaryLineEntityId: "line_1",
        secondaryLineEntityId: "line_2"
      }
    ]);

    const result = engine.applyBatch([
      {
        op: "sketch.deleteEntity",
        sketchId: "sketch_1",
        entityId: "point_fixed"
      },
      {
        op: "sketch.deleteEntity",
        sketchId: "sketch_1",
        entityId: "point_coincident"
      },
      {
        op: "sketch.deleteEntity",
        sketchId: "sketch_1",
        entityId: "point_midpoint"
      },
      {
        op: "sketch.deleteEntity",
        sketchId: "sketch_1",
        entityId: "line_2"
      }
    ]);

    expect(engine.getDocument().sketchDimensions.size).toBe(0);
    expect(engine.getDocument().sketchConstraints.size).toBe(0);
    expect(result.transaction.diff).toMatchObject({
      sketches: {
        entitiesDeleted: expect.arrayContaining([
          { sketchId: "sketch_1", id: "point_fixed", kind: "point" },
          { sketchId: "sketch_1", id: "point_coincident", kind: "point" },
          { sketchId: "sketch_1", id: "point_midpoint", kind: "point" },
          { sketchId: "sketch_1", id: "line_2", kind: "line" }
        ])
      },
      sketchConstraints: {
        deleted: expect.arrayContaining([
          expect.objectContaining({ id: "fixed_point" }),
          expect.objectContaining({ id: "coincident_point" }),
          expect.objectContaining({ id: "midpoint_point" }),
          expect.objectContaining({ id: "parallel_lines" })
        ])
      }
    });

    engine.undo();
    expect(engine.getDocument().sketchDimensions.size).toBe(1);
    expect(engine.getDocument().sketchConstraints.size).toBe(4);
    engine.redo();
    expect(engine.getDocument().sketchDimensions.size).toBe(0);
    expect(engine.getDocument().sketchConstraints.size).toBe(0);
  });

  it("validates sketch commands without mutating the document", () => {
    const engine = new CadEngine();

    const response = engine.executeBatch({
      version: "cadops.v1",
      mode: "commit",
      ops: [
        {
          op: "sketch.addRectangle",
          sketchId: "missing_sketch",
          center: [0, 0],
          width: 0,
          height: 1
        }
      ]
    });

    expect(response.ok).toBe(false);
    if (!response.ok) {
      expect(response.error).toMatchObject({
        code: "SKETCH_NOT_FOUND",
        op: "sketch.addRectangle",
        sketchId: "missing_sketch"
      });
    }
    expect(engine.getDocument().sketches.size).toBe(0);
  });

  it("supports sketch commands in batch dry-run and commit responses", () => {
    const engine = new CadEngine();
    const batch = {
      version: "cadops.v1" as const,
      mode: "dryRun" as const,
      ops: [
        {
          op: "sketch.create" as const,
          name: "Generated sketch",
          plane: "XY" as const
        },
        {
          op: "sketch.addPoint" as const,
          sketchId: "sketch_1",
          point: [1, 2] as const
        }
      ]
    };

    const dryRun = engine.executeBatch(batch);

    expect(dryRun).toMatchObject({
      ok: true,
      mode: "dryRun",
      createdSketchIds: ["sketch_1"],
      createdSketchEntityIds: ["skent_1"]
    });
    expect(engine.getDocument().sketches.size).toBe(0);

    const commit = engine.executeBatch({ ...batch, mode: "commit" });

    expect(commit).toMatchObject({
      ok: true,
      mode: "commit",
      createdSketchIds: ["sketch_1"],
      createdSketchEntityIds: ["skent_1"],
      transactionId: "txn_1"
    });
    expect(engine.getDocument().sketches.get("sketch_1")?.entities.size).toBe(
      1
    );
  });

