  it("updates simple body topology identity across source edits", () => {
    const engine = createRectangleExtrudeEngine();

    const initial = engine.executeQuery({
      version: "cadops.v1",
      query: { query: "body.topology", bodyId: "body_rect_1" }
    });
    if (!initial.ok || initial.query !== "body.topology") {
      throw new Error("Expected initial body topology response.");
    }

    engine.apply({
      op: "sketch.updateEntity",
      sketchId: "sketch_1",
      entity: {
        id: "rect_1",
        kind: "rectangle",
        center: [1, 2],
        width: 6,
        height: 5
      }
    });
    engine.apply({
      op: "feature.updateExtrude",
      id: "feat_rect_1",
      depth: 7,
      side: "symmetric"
    });

    const updated = engine.executeQuery({
      version: "cadops.v1",
      query: { query: "body.topology", bodyId: "body_rect_1" }
    });
    expect(updated).toMatchObject({
      ok: true,
      query: "body.topology",
      topology: {
        status: "healthy",
        sourceIdentity: {
          depth: 7,
          side: "symmetric",
          profileSignature: {
            kind: "rectangle",
            center: [1, 2],
            width: 6,
            height: 5
          }
        }
      }
    });

    if (updated.ok && updated.query === "body.topology") {
      expect(updated.topology.sourceIdentity.signature).not.toEqual(
        initial.topology.sourceIdentity.signature
      );
      expect(updated.topology.sourceIdentity.signature).toMatch(
        /^body-topology-source:v1:[a-f0-9]{64}$/
      );
      expect(updated.topology.sourceIdentity.signature).not.toContain(
        '"width":6'
      );
    } else {
      throw new Error("Expected updated body topology response.");
    }
  });

