  it("supports rectangle cut features targeting authored circle newBody bodies", () => {
    const engine = createCircleExtrudeEngine();

    engine.apply({
      op: "sketch.addRectangle",
      sketchId: "sketch_1",
      id: "rect_tool",
      center: [0, 0],
      width: 1,
      height: 1
    });

    const cutOp = {
      op: "feature.extrude" as const,
      id: "feat_circle_cut",
      bodyId: "body_circle_cut",
      targetBodyId: "body_circle_1",
      sketchId: "sketch_1",
      entityId: "rect_tool",
      depth: 1,
      operationMode: "cut" as const
    };
    const dryRun = engine.executeBatch({
      version: "cadops.v1",
      mode: "dryRun",
      ops: [cutOp]
    });
    const commit = engine.executeBatch({
      version: "cadops.v1",
      mode: "commit",
      ops: [cutOp]
    });
    const structure = engine.executeQuery({
      version: "cadops.v1",
      query: { query: "project.structure" }
    });
    const health = engine.executeQuery({
      version: "cadops.v1",
      query: { query: "project.health" }
    });
    const references = engine.executeQuery({
      version: "cadops.v1",
      query: {
        query: "body.generatedReferences",
        bodyId: "body_circle_cut"
      }
    });
    const targetMeasurements = engine.executeQuery({
      version: "cadops.v1",
      query: { query: "body.measurements", bodyId: "body_circle_1" }
    });
    const cutMeasurements = engine.executeQuery({
      version: "cadops.v1",
      query: { query: "body.measurements", bodyId: "body_circle_cut" }
    });
    const targetFaceMeasurement = engine.executeQuery({
      version: "cadops.v1",
      query: {
        query: "body.generatedReferenceMeasurements",
        bodyId: "body_circle_1",
        stableId: "generated:face:body_circle_1:endCap"
      }
    });
    const extents = engine.executeQuery({
      version: "cadops.v1",
      query: { query: "project.extents" }
    });
    const cutTransaction = engine
      .getTransactions()
      .find((transaction) =>
        transaction.ops.some(
          (op) => op.op === "feature.extrude" && op.id === "feat_circle_cut"
        )
      );

    expect(dryRun).toMatchObject({
      ok: true,
      createdFeatureIds: ["feat_circle_cut"],
      createdBodyIds: ["body_circle_cut"]
    });
    expect(commit).toMatchObject({
      ok: true,
      createdFeatureIds: ["feat_circle_cut"],
      createdBodyIds: ["body_circle_cut"]
    });
    expect(cutTransaction?.diff).toMatchObject({
      features: {
        created: [
          expect.objectContaining({
            id: "feat_circle_cut",
            operationMode: "cut",
            targetBodyId: "body_circle_1",
            bodyId: "body_circle_cut"
          })
        ],
        bodiesCreated: [{ id: "body_circle_cut", kind: "solid" }]
      }
    });
    expect(structure).toMatchObject({
      ok: true,
      query: "project.structure",
      features: expect.arrayContaining([
        expect.objectContaining({
          id: "feat_circle_cut",
          profileKind: "rectangle",
          operationMode: "cut",
          targetBodyId: "body_circle_1",
          bodyId: "body_circle_cut"
        })
      ]),
      bodies: expect.arrayContaining([
        expect.objectContaining({
          id: "body_circle_1",
          consumedByFeatureId: "feat_circle_cut"
        }),
        expect.objectContaining({
          id: "body_circle_cut",
          featureId: "feat_circle_cut"
        })
      ])
    });
    expect(health).toMatchObject({
      ok: true,
      query: "project.health",
      status: "under-defined",
      authoredExtrudes: expect.arrayContaining([
        expect.objectContaining({
          featureId: "feat_circle_cut",
          bodyId: "body_circle_cut",
          targetBodyId: "body_circle_1",
          operationMode: "cut",
          status: "healthy",
          issues: []
        })
      ])
    });
    expect(references).toMatchObject({
      ok: true,
      query: "body.generatedReferences",
      body: {
        stableId: "generated:body:body_circle_cut",
        eligibleOperations: []
      },
      faceCount: 4,
      faces: expect.arrayContaining([
        expect.objectContaining({
          stableId: "generated:face:body_circle_cut:side:uMin",
          label: "Cut wall face uMin"
        })
      ])
    });
    expect(targetMeasurements).toMatchObject({
      ok: true,
      query: "body.measurements",
      measurements: {
        bodyId: "body_circle_1",
        profileKind: "circle"
      }
    });
    if (
      targetMeasurements.ok &&
      targetMeasurements.query === "body.measurements"
    ) {
      expect(targetMeasurements.measurements.volume).toBeCloseTo(16 * Math.PI);
    } else {
      throw new Error(
        "Expected source measurements for consumed circle target."
      );
    }
    expect(cutMeasurements).toMatchObject({
      ok: false,
      query: "body.measurements",
      error: {
        code: "UNSUPPORTED_BODY_MEASUREMENTS",
        bodyId: "body_circle_cut"
      }
    });
    expect(targetFaceMeasurement).toMatchObject({
      ok: true,
      query: "body.generatedReferenceMeasurements",
      bodyId: "body_circle_1",
      stableId: "generated:face:body_circle_1:endCap",
      kind: "face",
      measurements: {
        kind: "face"
      }
    });
    expect(extents).toMatchObject({
      ok: true,
      query: "project.extents",
      bodyCount: 0,
      warnings: [
        {
          code: "DERIVED_EXACT_METADATA_MISSING",
          bodyId: "body_circle_cut",
          featureId: "feat_circle_cut"
        }
      ]
    });

    const consumedTarget = engine.executeBatch({
      version: "cadops.v1",
      mode: "dryRun",
      ops: [
        {
          ...cutOp,
          id: "feat_circle_cut_again",
          bodyId: "body_circle_cut_again"
        }
      ]
    });
    expect(consumedTarget).toMatchObject({
      ok: false,
      error: {
        code: "UNSUPPORTED_FEATURE_OPERATION",
        path: "$.ops[0].operationMode"
      }
    });

    const restored = importCadProjectJson(exportCadProjectJson(engine));
    expect(
      restored.getDocument().features.get("feat_circle_cut")
    ).toMatchObject({
      operationMode: "cut",
      targetBodyId: "body_circle_1",
      profileKind: "rectangle"
    });

    restored.undo();
    const undoneStructure = restored.executeQuery({
      version: "cadops.v1",
      query: { query: "project.structure" }
    });
    expect(restored.getDocument().features.has("feat_circle_cut")).toBe(false);
    expect(undoneStructure).toMatchObject({
      ok: true,
      query: "project.structure",
      bodies: [expect.objectContaining({ id: "body_circle_1" })]
    });
    if (!undoneStructure.ok || undoneStructure.query !== "project.structure") {
      throw new Error("Expected project.structure response.");
    }
    expect(
      undoneStructure.bodies.find((body) => body.id === "body_circle_1")
        ?.consumedByFeatureId
    ).toBeUndefined();

    restored.redo();
    expect(
      restored.executeQuery({
        version: "cadops.v1",
        query: { query: "project.structure" }
      })
    ).toMatchObject({
      ok: true,
      query: "project.structure",
      bodies: expect.arrayContaining([
        expect.objectContaining({
          id: "body_circle_1",
          consumedByFeatureId: "feat_circle_cut"
        }),
        expect.objectContaining({ id: "body_circle_cut" })
      ])
    });
  });

  it("supports circle cut tools and rejects consumed cut targets", () => {
    const engine = createRectangleExtrudeEngine();

    engine.apply({
      op: "sketch.addCircle",
      sketchId: "sketch_1",
      id: "circle_1",
      center: [0, 0],
      radius: 1
    });

    const circleTool = engine.executeBatch({
      version: "cadops.v1",
      mode: "commit",
      ops: [
        {
          op: "feature.extrude",
          id: "feat_circle_cut",
          bodyId: "body_circle_cut",
          targetBodyId: "body_rect_1",
          sketchId: "sketch_1",
          entityId: "circle_1",
          depth: 1,
          operationMode: "cut"
        }
      ]
    });
    const circleCutReferences = engine.executeQuery({
      version: "cadops.v1",
      query: {
        query: "body.generatedReferences",
        bodyId: "body_circle_cut"
      }
    });
    const circleCutWallSelection = engine.executeQuery({
      version: "cadops.v1",
      query: {
        query: "selection.referenceCandidates",
        selection: {
          type: "generatedReference",
          bodyId: "body_circle_cut",
          stableId: "generated:face:body_circle_cut:side:circular",
          expectedKind: "face"
        },
        requiredOperation: "feature.measureReference"
      }
    });
    const circleCutWallMeasurements = engine.executeQuery({
      version: "cadops.v1",
      query: {
        query: "body.generatedReferenceMeasurements",
        bodyId: "body_circle_cut",
        stableId: "generated:face:body_circle_cut:side:circular"
      }
    });
    const circleCutRimMeasurements = engine.executeQuery({
      version: "cadops.v1",
      query: {
        query: "body.generatedReferenceMeasurements",
        bodyId: "body_circle_cut",
        stableId: "generated:edge:body_circle_cut:end:circular"
      }
    });

    expect(circleTool).toMatchObject({
      ok: true,
      createdFeatureIds: ["feat_circle_cut"],
      createdBodyIds: ["body_circle_cut"]
    });
    expect(circleCutReferences).toMatchObject({
      ok: true,
      query: "body.generatedReferences",
      body: {
        stableId: "generated:body:body_circle_cut",
        eligibleOperations: []
      },
      faceCount: 1,
      faces: [
        expect.objectContaining({
          stableId: "generated:face:body_circle_cut:side:circular",
          label: "Cut circular wall face",
          eligibleOperations: [
            "feature.shell",
            "feature.measureReference",
            "feature.selectReference"
          ],
          geometricSignature: expect.objectContaining({
            profileKind: "circle",
            extrudeOperationMode: "cut",
            surfaceType: "cylinder",
            axisRole: "cutWall:side:circular"
          })
        })
      ],
      edgeCount: 2,
      edges: expect.arrayContaining([
        expect.objectContaining({
          stableId: "generated:edge:body_circle_cut:start:circular",
          label: "Cut start circular rim edge",
          eligibleOperations: [
            "feature.measureReference",
            "feature.selectReference"
          ]
        }),
        expect.objectContaining({
          stableId: "generated:edge:body_circle_cut:end:circular",
          label: "Cut terminal circular rim edge"
        })
      ])
    });
    expect(circleCutWallSelection).toMatchObject({
      ok: true,
      query: "selection.referenceCandidates",
      status: "resolved",
      candidates: [
        expect.objectContaining({
          commandable: true,
          commandOperations: expect.arrayContaining([
            "reference.nameGenerated",
            "feature.measureReference",
            "feature.selectReference"
          ])
        })
      ]
    });
    expect(circleCutWallMeasurements).toMatchObject({
      ok: true,
      query: "body.generatedReferenceMeasurements",
      kind: "face",
      measurements: {
        kind: "face",
        role: "side:circular",
        surfaceType: "cylinder",
        axisRole: "cutWall:side:circular"
      }
    });
    if (
      circleCutWallMeasurements.ok &&
      circleCutWallMeasurements.query ===
        "body.generatedReferenceMeasurements" &&
      circleCutWallMeasurements.measurements.kind === "face"
    ) {
      expect(circleCutWallMeasurements.measurements.area).toBeCloseTo(
        2 * Math.PI
      );
    }
    expect(circleCutRimMeasurements).toMatchObject({
      ok: true,
      query: "body.generatedReferenceMeasurements",
      kind: "edge",
      measurements: {
        kind: "edge",
        role: "end:circular",
        curveType: "circle",
        axisRole: "cutTerminalRim:circular"
      }
    });
    if (
      circleCutRimMeasurements.ok &&
      circleCutRimMeasurements.query ===
        "body.generatedReferenceMeasurements" &&
      circleCutRimMeasurements.measurements.kind === "edge"
    ) {
      expect(circleCutRimMeasurements.measurements.length).toBeCloseTo(
        2 * Math.PI
      );
    }

    const consumedTarget = engine.executeBatch({
      version: "cadops.v1",
      mode: "dryRun",
      ops: [
        {
          op: "feature.extrude",
          id: "feat_cut_again",
          bodyId: "body_cut_again",
          targetBodyId: "body_rect_1",
          sketchId: "sketch_1",
          entityId: "rect_1",
          depth: 1,
          operationMode: "cut"
        }
      ]
    });
    const deleteTarget = engine.executeBatch({
      version: "cadops.v1",
      mode: "dryRun",
      ops: [{ op: "feature.delete", id: "feat_rect_1" }]
    });

    expect(consumedTarget).toMatchObject({
      ok: false,
      error: {
        code: "UNSUPPORTED_FEATURE_OPERATION",
        path: "$.ops[0].operationMode"
      }
    });
    expect(deleteTarget).toMatchObject({
      ok: false,
      error: {
        code: "FEATURE_NOT_DELETABLE",
        featureId: "feat_rect_1",
        bodyId: "body_rect_1"
      }
    });
  });

