  it("creates, renames, deletes, undoes, and redoes horizontal and vertical line constraints", () => {
    const engine = new CadEngine();
    const created = engine.executeBatch({
      version: "cadops.v1",
      mode: "commit",
      ops: [
        { op: "sketch.create", id: "sketch_1", name: "Profile", plane: "XY" },
        {
          op: "sketch.addLine",
          sketchId: "sketch_1",
          id: "line_1",
          start: [0, 0],
          end: [3, 4]
        },
        {
          op: "sketch.constraint.create",
          id: "con_horizontal",
          name: "Horizontal line",
          sketchId: "sketch_1",
          entityId: "line_1",
          kind: "horizontal"
        }
      ]
    });

    expect(created).toMatchObject({
      ok: true,
      createdSketchConstraintIds: ["con_horizontal"],
      modifiedSketchEntityIds: ["line_1"]
    });
    expect(
      engine.executeQuery({
        version: "cadops.v1",
        query: { query: "sketch.get", id: "sketch_1" }
      })
    ).toMatchObject({
      ok: true,
      sketch: {
        entities: [
          {
            id: "line_1",
            kind: "line",
            start: [-1, 2],
            end: [4, 2]
          }
        ]
      }
    });
    expect(engine.getTransactions()[0]?.diff).toMatchObject({
      sketchConstraints: {
        created: [
          {
            id: "con_horizontal",
            name: "Horizontal line",
            sketchId: "sketch_1",
            entityId: "line_1",
            kind: "horizontal"
          }
        ]
      },
      sketches: {
        entitiesModified: [{ sketchId: "sketch_1", id: "line_1", kind: "line" }]
      }
    });

    engine.apply({
      op: "sketch.constraint.rename",
      id: "con_horizontal",
      name: "Main horizontal"
    });
    expect(engine.getTransactions().at(-1)?.diff).toMatchObject({
      sketchConstraints: {
        modified: [{ id: "con_horizontal", name: "Main horizontal" }]
      }
    });

    engine.apply({ op: "sketch.constraint.delete", id: "con_horizontal" });
    expect(
      engine.executeQuery({
        version: "cadops.v1",
        query: { query: "sketch.evaluation", sketchId: "sketch_1" }
      })
    ).toMatchObject({
      ok: true,
      constraintCount: 0,
      constraints: []
    });

    engine.undo();
    expect(
      engine.executeQuery({
        version: "cadops.v1",
        query: { query: "sketch.evaluation", sketchId: "sketch_1" }
      })
    ).toMatchObject({
      ok: true,
      status: "under-defined",
      drivenEntityIds: ["line_1"],
      constraintCount: 1,
      constraints: [
        expect.objectContaining({
          id: "con_horizontal",
          name: "Main horizontal",
          kind: "horizontal",
          status: "healthy"
        })
      ]
    });

    engine.redo();
    expect(
      engine.executeQuery({
        version: "cadops.v1",
        query: { query: "sketch.evaluation", sketchId: "sketch_1" }
      })
    ).toMatchObject({
      ok: true,
      constraintCount: 0
    });

    engine.apply({
      op: "sketch.constraint.create",
      id: "con_vertical",
      name: "Vertical line",
      sketchId: "sketch_1",
      entityId: "line_1",
      kind: "vertical"
    });
    expect(
      engine.executeQuery({
        version: "cadops.v1",
        query: { query: "sketch.get", id: "sketch_1" }
      })
    ).toMatchObject({
      ok: true,
      sketch: {
        entities: [
          {
            id: "line_1",
            kind: "line",
            start: [1.5, -0.5],
            end: [1.5, 4.5]
          }
        ]
      }
    });
  });

