        expect.objectContaining({
          code: "WCAD_BYTE_LENGTH_MISMATCH",
          entryRole: "document"
        }),
        expect.objectContaining({
          code: "WCAD_HASH_MISMATCH",
          entryPath: "document.cbor"
        })
